# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests

def lambda_handler(event, context):
    request = event["Records"][0]["cf"]["request"]
    headers = request.get("headers", {})

    enrich_urls = []

    if "x-enrich-url" in headers:
        for item in headers["x-enrich-url"]:
            value = item.get("value", "").strip()
            if value:
                enrich_urls.append(value)

    enrich_data = []
    errors = []

    for url in enrich_urls:
        try:
            resp = requests.get(url, timeout=2)
            content_type = resp.headers.get("Content-Type", "")
            if "application/json" in content_type:
                body = resp.json()
            else:
                body = resp.text

            enrich_data.append({
                "url": url,
                "status_code": resp.status_code,
                "data": body
            })
        except Exception as e:
            errors.append({
                "url": url,
                "error": str(e)
            })

    if enrich_data or errors:
        request_headers = request.setdefault("headers", {})
        request_headers["x-enrich-result"] = [{
            "key": "X-Enrich-Result",
            "value": json.dumps({
                "results": enrich_data,
                "errors": errors
            }, separators=(",", ":"))
        }]

    return request